// Custom checked exception (extends Exception)
class InsufficientFundsException extends Exception {
    // Constructor with message
    public InsufficientFundsException(String message) {
        super(message);
    }

    // Constructor with message and cause
    public InsufficientFundsException(String message, Throwable cause) {
        super(message, cause);
    }
}

// Custom unchecked exception (extends RuntimeException)
class NegativeAmountException extends RuntimeException {
    public NegativeAmountException(String message) {
        super(message);
    }
}

class BankAccount {
    private String accountNumber;
    private double balance;

    BankAccount(String accountNumber, double initialBalance) {
        this.accountNumber = accountNumber;
        this.balance = initialBalance;
    }

    public void withdraw(double amount) throws InsufficientFundsException {
        if (amount < 0) {
            throw new NegativeAmountException("Cannot withdraw negative amount!");
        }

        if (amount > balance) {
            throw new InsufficientFundsException(
                "Insufficient funds! Balance: $" + balance + ", Requested: $" + amount
            );
        }

        balance -= amount;
        System.out.println("Withdrew $" + amount + ". New balance: $" + balance);
    }

    public void deposit(double amount) {
        if (amount < 0) {
            throw new NegativeAmountException("Cannot deposit negative amount!");
        }
        balance += amount;
        System.out.println("Deposited $" + amount + ". New balance: $" + balance);
    }

    public double getBalance() {
        return balance;
    }
}

public class CustomExceptionExample {
    public static void main(String[] args) {
        BankAccount account = new BankAccount("12345", 500);

        System.out.println("Initial balance: $" + account.getBalance());

        // Deposit — NegativeAmountException (unchecked)
        try {
            account.deposit(-100);
        } catch (NegativeAmountException e) {
            System.out.println("Deposit error: " + e.getMessage());
        }

        // Withdraw — InsufficientFundsException (checked)
        try {
            account.withdraw(1000);
        } catch (InsufficientFundsException e) {
            System.out.println("Withdrawal error: " + e.getMessage());
            System.out.println("Current balance: $" + account.getBalance());
        } catch (NegativeAmountException e) {
            System.out.println("Withdrawal error: " + e.getMessage());
        }

        // Successful withdrawal
        try {
            account.withdraw(200);
        } catch (Exception e) {
            System.out.println("Error: " + e.getMessage());
        }

        System.out.println("Final balance: $" + account.getBalance());
    }
}

