class AgeException extends Exception {
    public AgeException(String message) {
        super(message);
    }
}

class Person {
    private String name;
    private int age;

    Person(String name, int age) throws AgeException {
        if (age < 0 || age > 150) {
            throw new AgeException("Invalid age: " + age + "! Must be 0-150.");
        }
        this.name = name;
        this.age = age;
    }

    void vote() throws AgeException {
        if (age < 18) {
            throw new AgeException("Cannot vote! Age " + age + " is under 18.");
        }
        System.out.println(name + " is voting!");
    }
}

public class Main {
    public static void main(String[] args) {
        try {
            Person p1 = new Person("Alice", 20);
            p1.vote();

            Person p2 = new Person("Bob", 15);
            p2.vote();

        } catch (AgeException e) {
            System.out.println("Error: " + e.getMessage());
        }

        try {
            Person p3 = new Person("Charlie", -5);
        } catch (AgeException e) {
            System.out.println("Error: " + e.getMessage());
        }
    }
}
